<script>
(function () {
  var devices = {};
  var activeDevice = null;
  var initialLoadComplete = false;

  var tabsEl = document.getElementById('tabs');
  var logArea = document.getElementById('log-area');
  var placeholder = document.getElementById('placeholder');

  function createDevice(name) {
    if (devices[name]) return;

    placeholder.style.display = 'none';

    // Tab
    var tab = document.createElement('div');
    tab.className = 'tab';
    tab.dataset.device = name;

    var tabName = document.createElement('span');
    tabName.className = 'tab-name';
    tabName.textContent = name;
    tab.appendChild(tabName);

    var totalBadge = document.createElement('span');
    totalBadge.className = 'total';
    totalBadge.textContent = '(0)';
    tab.appendChild(totalBadge);
    tab.onclick = function () { switchTab(name); };
    tabsEl.appendChild(tab);

    // Panel
    var panel = document.createElement('div');
    panel.className = 'log-panel';

    var lines = document.createElement('div');
    lines.className = 'log-lines';

    var footer = document.createElement('div');
    footer.className = 'panel-footer';

    var footerLeft = document.createElement('div');
    footerLeft.className = 'footer-left';
    var scrollCb = document.createElement('input');
    scrollCb.type = 'checkbox';
    scrollCb.checked = true;
    scrollCb.id = 'scroll-' + name;
    var scrollLabel = document.createElement('label');
    scrollLabel.htmlFor = scrollCb.id;
    scrollLabel.textContent = 'Auto-scroll';
    footerLeft.appendChild(scrollCb);
    footerLeft.appendChild(scrollLabel);

    var footerRight = document.createElement('div');
    footerRight.className = 'footer-right';

    var exportBtn = document.createElement('button');
    exportBtn.className = 'btn';
    exportBtn.textContent = 'Export';
    exportBtn.onclick = function () {
      var text = '';
      var logLines = lines.querySelectorAll('.log-line');
      for (var i = 0; i < logLines.length; i++) {
        text += logLines[i].textContent + '\\n';
      }
      var blob = new Blob([text], { type: 'text/plain' });
      var a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = name + '_logs.txt';
      a.click();
      URL.revokeObjectURL(a.href);
    };

    var clearBtn = document.createElement('button');
    clearBtn.className = 'btn';
    clearBtn.textContent = 'Clear';
    clearBtn.onclick = function () {
      lines.innerHTML = '';
      var d = devices[name];
      d.total = 0;
      d.unread = 0;
      var totalBadge = d.tab.querySelector('.total');
      if (totalBadge) totalBadge.textContent = '(0)';
      var badge = d.tab.querySelector('.badge');
      if (badge) badge.remove();
      localStorage.removeItem('logfire_read_' + name);
      fetch('/clear', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ device: name })
      }).catch(function () {});
    };

    footerRight.appendChild(exportBtn);
    footerRight.appendChild(clearBtn);
    footer.appendChild(footerLeft);
    footer.appendChild(footerRight);
    panel.appendChild(lines);
    panel.appendChild(footer);
    logArea.appendChild(panel);

    devices[name] = { tab: tab, panel: panel, lines: lines, unread: 0, total: 0, autoScroll: scrollCb };

    scrollCb.onchange = function () {
      if (scrollCb.checked) lines.scrollTop = lines.scrollHeight;
    };

    // Activate first device automatically
    if (!activeDevice) switchTab(name);
  }

  function switchTab(name) {
    if (!devices[name]) return;

    // Deactivate current
    if (activeDevice && devices[activeDevice]) {
      devices[activeDevice].tab.className = 'tab';
      devices[activeDevice].panel.className = 'log-panel';
    }

    activeDevice = name;
    var d = devices[name];
    d.tab.className = 'tab active';
    d.panel.className = 'log-panel active';

    // Clear unread badge and persist read state
    d.unread = 0;
    var badge = d.tab.querySelector('.badge');
    if (badge) badge.remove();
    localStorage.setItem('logfire_read_' + name, new Date().toISOString());

    // Scroll to bottom if auto-scroll is on
    if (d.autoScroll.checked) d.lines.scrollTop = d.lines.scrollHeight;
  }

  function addLog(entry) {
    var name = entry.device;
    createDevice(name);

    var d = devices[name];
    var time = new Date(entry.timestamp);
    var hh = String(time.getHours()).padStart(2, '0');
    var mm = String(time.getMinutes()).padStart(2, '0');
    var ss = String(time.getSeconds()).padStart(2, '0');

    var line = document.createElement('div');
    line.className = 'log-line';
    line.textContent = '[' + hh + ':' + mm + ':' + ss + '] ' + entry.message;
    d.lines.appendChild(line);

    // Update total count
    d.total++;
    var totalBadge = d.tab.querySelector('.total');
    if (totalBadge) totalBadge.textContent = '(' + d.total + ')';

    // Auto-scroll if active tab and auto-scroll enabled
    if (name === activeDevice && d.autoScroll.checked) {
      d.lines.scrollTop = d.lines.scrollHeight;
    } else if (name !== activeDevice && initialLoadComplete) {
      // Increment unread badge (only for live messages)
      d.unread++;
      var badge = d.tab.querySelector('.badge');
      if (!badge) {
        badge = document.createElement('span');
        badge.className = 'badge';
        d.tab.appendChild(badge);
      }
      badge.textContent = d.unread;
    }
  }

  // Load existing logs on page load
  fetch('/logs')
    .then(function (res) { return res.json(); })
    .then(function (logs) {
      var deviceNames = Object.keys(logs);
      deviceNames.forEach(function (name) {
        createDevice(name);
        logs[name].forEach(function (entry) { addLog(entry); });
      });

      // Restore unread badges from localStorage
      deviceNames.forEach(function (name) {
        if (name === activeDevice) return;
        var d = devices[name];
        var lastRead = localStorage.getItem('logfire_read_' + name);
        var unreadCount = 0;
        if (!lastRead) {
          // Never viewed — all messages are unread
          unreadCount = d.total;
        } else {
          var entries = logs[name] || [];
          for (var i = 0; i < entries.length; i++) {
            if (entries[i].timestamp > lastRead) unreadCount++;
          }
        }
        if (unreadCount > 0) {
          d.unread = unreadCount;
          var badge = document.createElement('span');
          badge.className = 'badge';
          badge.textContent = unreadCount;
          d.tab.appendChild(badge);
        }
      });

      initialLoadComplete = true;
    })
    .catch(function () {});

  // Connect WebSocket for live updates
  var wsProto = location.protocol === 'https:' ? 'wss:' : 'ws:';
  var ws = new WebSocket(wsProto + '//' + location.host + '/ws/logs');

  ws.onmessage = function (evt) {
    try {
      var entry = JSON.parse(evt.data);
      addLog(entry);
    } catch (e) {}
  };

  ws.onclose = function () {
    // Attempt reconnect after 3s
    setTimeout(function () { location.reload(); }, 3000);
  };
})();
</script>

</body>
</html>
